            </motion.h2>

            {/* Projects Container Wrapper for 3D Perspective */}
            <div style={{ perspective: "1200px" }} className="w-full flex justify-center">
                <motion.div
                    className="w-full flex flex-col gap-24 md:gap-40 lg:gap-56 max-w-[1700px]"
                    variants={containerVariants}
                    initial="hidden"
                    whileInView="show"
                    viewport={{ once: true, margin: "-100px" }}
                    style={{ transformStyle: "preserve-3d" }}
                >
                    {/* Project 1: TEAURE */}
                <ProjectCard
                    index="01"
                    category="E-COMMERCE"
                    targetYear="2026"
                    title="TEAURE"
                    description="Organic blends crafted for calm, presence, and unmatched holistic purity."
                    videoSrc="https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/ForBiggerBlazes.mp4"
                    containerVariants={containerVariants}
                    itemVariants={itemVariants}
                />

                {/* Project 2: CREATIVE ANTS */}
